INSERT INTO `rss_items` VALUES (1,1,'Pelantikan Ormawa UIN Ar-Raniry, Rektor Ajak Mahasiswa Junjung Etika dan Dialog','https://warta.ar-raniry.ac.id/2026/05/pelantikan-ormawa-uin-ar-raniry-rektor-ajak-mahasiswa-junjung-etika-dan-dialog/','Banda Aceh (Ar-Raniry) ΓÇö Rektor Prof Dr Mujiburrahman MAg resmi melantik pengurus Dewan Eksekutif Mahasiswa (DEMA) dan Senat Mahasiswa (SEMA) UIN Ar-Raniry periode 2026ΓÇô2027 dalam prosesi pelantikan bersama organisasi kemahasiswaan yang berlangsung di Auditorium Prof Ali Hasjmy, Minggu (24/5/202...','Futri Muliana','2026-05-25 02:21:38','https://warta.ar-raniry.ac.id/wp-content/uploads/2026/05/WhatsApp-Image-2026-05-25-at-08.30.32-300x200.jpeg','2026-05-25 03:02:06'),(2,1,'Rektor UIN Ar-Raniry: Pujian Kepala BKN Perkuat Sosok Menag dalam Buku Teladan Sang Menteri','https://warta.ar-raniry.ac.id/2026/05/rektor-uin-ar-raniry-pujian-kepala-bkn-perkuat-sosok-menag-dalam-buku-teladan-sang-menteri/','Jakarta (Ar-Raniry) ΓÇö Kepala Badan Kepegawaian Negara (BKN), Zudan Arif Fakrulloh, memuji kepemimpinan Menteri Agama RI Nasaruddin Umar yang dinilai berhasil menghadirkan keteladanan moral, integritas, dan budaya birokrasi humanis di lingkungan aparatur sipil negara (ASN). Pernyataan itu disampaik...','Raihana Salsabilla','2026-05-23 04:41:02','https://warta.ar-raniry.ac.id/wp-content/uploads/2026/05/WhatsApp-Image-2026-05-23-at-11.36.49-300x201.jpeg','2026-05-25 03:02:06'),(3,1,'Kepala BKN Puji Kepemimpinan Nasaruddin Umar, Sebut Menag sebagai Role Model ASN Indonesia','https://warta.ar-raniry.ac.id/2026/05/kepala-bkn-puji-kepemimpinan-nasaruddin-umar-sebut-menag-sebagai-role-model-asn-indonesia/','Jakarta (Ar-Raniry) ΓÇö Kepala Badan Kepegawaian Negara (BKN), Zudan Arif Fakrulloh, memuji kepemimpinan Menteri Agama RI Nasaruddin Umar yang dinilai berhasil menghadirkan keteladanan moral, integritas, dan budaya birokrasi humanis di lingkungan aparatur sipil negara (ASN). Pernyataan itu disampaik...','Raihana Salsabilla','2026-05-23 04:3